const inp = msg.payload
const weekly_hours = flow.get("contract.weekly_hours")
let grouping = flow.get("grouping")

// Group by calendarweek
if (grouping == 0) {
    for (let group of inp) {
        let expected_work_time = weekly_hours[group.year][group.calendar_week]
        if (group.total_time >= expected_work_time["daily_hours"] * expected_work_time["days"]) {
            group["target_reached"] = "Yes"
        } else {
            group["target_reached"] = "No"
        }
    }
} else if (grouping == 1) {
    for (let group of inp) {
        let expected_work_time = weekly_hours[group.year][group.calendar_week]
        if (group.total_time >= expected_work_time["daily_hours"]) {
            group["target_reached"] = "Yes"
        } else {
            group["target_reached"] = "No"
        }
    }
}

return msg;
